function toIso(value) {
  if (!value) return null;
  const date = new Date(value);
  return isNaN(date.getTime()) ? null : date.toISOString();
}

function normalizeAuthor(author) {
  if (!author) return null;
  if (typeof author === 'string') return author.trim() || null;
  if (Array.isArray(author)) {
    return author.map(a => normalizeAuthor(a)).filter(Boolean).join(', ') || null;
  }
  if (typeof author === 'object') {
    return author.email || author.name || author.username || author.id || null;
  }
  return null;
}

function normalizeTags(raw) {
  if (!Array.isArray(raw)) return null;
  const result = raw
    .map(t => (typeof t === 'string' ? t.trim() : (t.name || t.id || '')))
    .filter(Boolean);
  return result.length > 0 ? result : null;
}

return $input.all().map(item => {
  const v = item.json;

  return {
    json: {
      workflow_id:      v.workflow_id || v.workflowId || v.id || null,
      workflow_name:    v.workflow_name || v.name || null,
      active:           v.active ?? null,
      archived:         v.isArchived ?? v.archived ?? null,
      owner_project_id: v.owner_project_id || v.ownerProjectId || v.projectId || null,

      version_id:       v.version_id || v.versionId || v.id || null,

      last_modified_by: normalizeAuthor(
        v.version_author || v.versionAuthor ||
        v.author || v.createdBy || v.updatedBy || null
      ),

      version_created_at:  toIso(v.version_created_at  || v.versionCreatedAt  || v.createdAt),
      workflow_created_at: toIso(v.workflow_created_at  || v.createdAt),
      workflow_updated_at: toIso(v.workflow_updated_at  || v.updatedAt),

      description: v.description || null,
      tags:        normalizeTags(v.tags),
      synced_at:   new Date().toISOString(),
    }
  };
});

const input = $input.all();

const workflows = input.flatMap(item => {
  const json = item.json;
  if (Array.isArray(json.data)) return json.data;
  return [json];
});

function toIso(value) {
  if (!value) return null;
  const date = new Date(value);
  return isNaN(date.getTime()) ? null : date.toISOString();
}

function normalizeTags(raw) {
  if (!Array.isArray(raw)) return null;
  const result = raw
    .map(t => (typeof t === 'string' ? t.trim() : (t.name || t.id || '')))
    .filter(Boolean);
  return result.length > 0 ? result : null;
}

const rows = workflows
  .filter(wf => wf.id || wf.workflow_id)
  .map(wf => {
    const activeVersion =
      wf.activeVersion ||
      wf.version ||
      wf.latestVersion ||
      {};

    const versionAuthor =
      wf.version_author ||
      wf.versionAuthor ||
      wf.lastModifiedBy ||
      wf.updatedBy ||
      activeVersion.author ||
      {};

    const ownerProject =
      wf.project ||
      wf.homeProject ||
      wf.ownerProject ||
      wf.shared?.find?.(s =>
        String(s.role || '').toLowerCase().includes('owner')
      )?.project ||
      {};

    return {
      workflow_id: wf.id || wf.workflow_id,
      workflow_name: wf.name || wf.workflow_name || '(Untitled workflow)',

      active: wf.active ?? null,
      archived: wf.archived ?? null,

      owner_project_id:
        wf.owner_project_id ||
        wf.ownerProjectId ||
        wf.projectId ||
        ownerProject.id ||
        null,

      version_id:
        wf.versionId ||
        wf.version_id ||
        activeVersion.id ||
        null,

      last_modified_by:
        typeof versionAuthor === 'string'
          ? versionAuthor
          : versionAuthor.email ||
            versionAuthor.name ||
            wf.last_modified_by ||
            null,

      version_created_at:
        toIso(
          wf.version_created_at ||
          wf.versionCreatedAt ||
          activeVersion.createdAt ||
          wf.updatedAt
        ),

      workflow_created_at:
        toIso(wf.createdAt || wf.workflow_created_at),

      workflow_updated_at:
        toIso(wf.updatedAt || wf.workflow_updated_at),

      // ── NEW FIELDS ──────────────────────────────────────────
      description:
        wf.description ||
        wf.meta?.description ||
        null,

      tags: normalizeTags(wf.tags),
      // ────────────────────────────────────────────────────────

      synced_at: new Date().toISOString(),
    };
  });

return [
  {
    json: {
      rows,
      count: rows.length,
    },
  },
];

return $input.all().map(item => {
  const wf = item.json;

  return {
    json: {
      workflow_id:         wf.id || wf.workflow_id || null,
      version_id:          wf.versionId || wf.version_id || null,
      workflow_name:       wf.name || wf.workflow_name || null,  // ← ADD
      active:              wf.active ?? null,                    // ← ADD
      archived:            wf.archived ?? null,                  // ← ADD
      owner_project_id:    wf.projectId || wf.ownerProjectId || wf.homeProject?.id || wf.project?.id || null, // ← ADD
      workflow_created_at: wf.createdAt || null,                 // ← ADD
      workflow_updated_at: wf.updatedAt || null,                 // ← ADD
      description:         wf.meta?.description || wf.description || null,
      tags: (() => {
        const raw = wf.tags;
        if (!Array.isArray(raw)) return null;
        const result = raw
          .map(t => (typeof t === 'string' ? t.trim() : (t.name || t.id || '')))
          .filter(Boolean);
        return result.length > 0 ? result : null;
      })(),
    }
  };
});

const results = [];

for (const item of $input.all()) {
  const wf = item.json;

  if (!wf.active) continue;

  const name = wf.name || wf.workflow_name || 'untitled';
  const slug = name
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '');

  const exportPayload = {
    name: wf.name,
    nodes: wf.nodes || [],
    connections: wf.connections || {},
    settings: wf.settings || {},
    pinData: wf.pinData || {},
    active: wf.active,
    tags: wf.tags || [],
    id: wf.id,
    meta: wf.meta || {}
  };

  results.push({
    json: {
      path: `workflows/${slug}.json`,
      fileContent: JSON.stringify(exportPayload, null, 2),
      message: `sync: ${name} (${new Date().toISOString()})`,
      workflow_id: wf.id
    }
  });
}

return results;

